class ContributionReviewGate:
    def __init__(self, request: ContributionRequest):
        self.request = request
        self._audit_log = []

    def gate_a_ip_screen(self) -> dict:
        r = self.request
        issues = []
        # Check for trade secrets: large novel algorithms are high risk
        if r.contains_novel_algorithm and r.ip_risk_score >= 4:
            issues.append(
                'Novel algorithm with high IP risk score — check patent '
                'landscape before disclosing in public PR'
            )
        # Check for benchmark data exposure
        if r.contains_benchmark_data:
            issues.append(
                'Benchmark data included — verify dataset is not derived '
                'from proprietary internal evaluation sets'
            )
        # Check for proprietary prompt templates
        if r.contains_prompt_templates and r.contribution_type == ContributionType.FEATURE:
            issues.append(
                'Prompt templates in feature contribution — review whether '
                'templates encode proprietary system-prompt design decisions'
            )
        result = {
            'gate': 'A_IP_SCREEN',
            'passed': len(issues) == 0,
            'issues': issues,
        }
        self._audit_log.append(result)
        return result

    def gate_b_legal_review(self) -> dict:
        r = self.request
        issues = []
        if not r.cla_signed:
            issues.append(
                'CLA not signed — contribution cannot proceed without '
                'a signed Contributor Licence Agreement on file'
            )
        if r.requires_legal_review and not r.patent_search_done:
            issues.append(
                'Legal review required but patent search not completed — '
                'submit to legal before opening upstream PR'
            )
        # Inbound licence compatibility
        if r.target_project_licence in {'GPL-3.0-only', 'AGPL-3.0-only'}:
            issues.append(
                'Outbound licence is {lic} — contributed code becomes '
                '{lic} licensed. Confirm this is acceptable for any '
                'IP the employee is contributing on behalf of the organisation.'
                .format(lic=r.target_project_licence)
            )
        result = {
            'gate': 'B_LEGAL_REVIEW',
            'passed': len(issues) == 0,
            'issues': issues,
        }
        self._audit_log.append(result)
        return result

    def gate_c_security_review(self) -> dict:
        r = self.request
        issues = []
        # Internal architecture exposure check
        if r.contribution_type == ContributionType.INFRASTRUCTURE:
            issues.append(
                'Infrastructure contribution — review for accidental '
                'disclosure of internal network topology, credentials, '
                'or deployment architecture in code, comments, or git history'
            )
        # Dataset privacy check
        if r.data_included:
            issues.append(
                'Data included in contribution — confirm no personal data, '
                'customer data, or PII is present in the contributed dataset '
                'or example files'
            )
        result = {
            'gate': 'C_SECURITY_REVIEW',
            'passed': len(issues) == 0,
            'issues': issues,
        }
        self._audit_log.append(result)
        return result

    def run_all_gates(self) -> ReviewOutcome:
        ga = self.gate_a_ip_screen()
        gb = self.gate_b_legal_review()
        gc = self.gate_c_security_review()
        if not ga['passed']:
            self.request.review_outcome = ReviewOutcome.REJECTED
        elif not gb['passed']:
            self.request.review_outcome = ReviewOutcome.HOLD
        elif not gc['passed']:
            self.request.review_outcome = ReviewOutcome.HOLD
        else:
            self.request.review_outcome = ReviewOutcome.APPROVED
        return self.request.review_outcome
